"""
MKT Original Language Commentary — Psalms chapters 18–21
Run: python3 scripts/zc-original-psalms-18-21.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json (MKT text)

Key decisions in this range:
- Ps 18:1 ʾerḥāmĕkā: MKT "I love you" — Hebrew root rāḥam (womb/tender compassion),
  the only occurrence of this verb directed to God; unusually intimate.
- Ps 18:2 merechav stacked metaphors: the six images (rock/fortress/rescuer/shield/
  horn/stronghold) function as an accumulating declaration, not distinguishable claims.
- Ps 18:7-15 theophany: storm-warrior imagery drawn from ANE divine-warrior traditions
  (El/Baal iconography), but now describing YHWH's descent to rescue David.
- Ps 18:25-26 divine mirror principle: the niphal reflexives show God "acting as X"
  toward those who are X — not a character change in God but a consistent response.
- Ps 18:49 cited in Rom 15:9 as Gentile-worship proof text.
- Ps 19:3-4 paradox of creation's silent speech: Paul cites v4 in Rom 10:18.
- Ps 19:7-9 six-fold description of the Word: each attribute/effect pair is carefully
  balanced; tôrāh/tāmîm = instruction/unblemished (the vocabulary of sacrifice).
- Ps 19:12-13 two classes of sin: nistarôt (hidden/unknown) vs zēdîm (willful/
  presumptuous) — corresponds to Num 15 inadvertent vs deliberate sin categories.
- Ps 20:9 MT is difficult; MKT takes it as two separate petitions.
- Ps 21:4 ʿōlām wāʿed: "forever and ever" — the phrase of eternal duration applied
  to the king, anticipating Messianic fulfillment in Heb 1:8 register.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original commentary for Psalms 18–21 — the great royal victory song (Ps 18),
#   the two-scroll psalm of creation and Torah speech (Ps 19), the pre-battle liturgy
#   (Ps 20), and the royal thanksgiving (Ps 21). Focus on theophany imagery in Ps 18:7-15,
#   the divine mirror principle in 18:25-26, the paradox of silent cosmic speech in 19:3-4,
#   and the two categories of sin in 19:12-13.
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(18,22)])"

PSALMS = {
  "18": {
    "1": '<p>The superscription identifies this as David\'s victory song, paralleled in 2 Sam 22. <strong>אֶרְחָמְךָ יְהוָה חִזְקִי</strong> (<em>ʾerḥāmĕkā YHWH ḥizqî</em>, "I love you, LORD, my strength") — the verb <em>rāḥam</em> is from the root <em>reḥem</em> (womb): the tender, womb-like compassion a mother has for her child. Nowhere else in the Psalter is this verb used for the Psalmist\'s love toward God — it is normally used of God\'s compassion for humans (Ps 103:13). The opening is uniquely intimate: David declares a tender, interior attachment rather than the more conventional honor-vocabulary.</p>',
    "2": '<p>Six metaphors accumulate without pause: <strong>סַלְעִי</strong> (<em>salʿî</em>, "my rock" — a cliff-face of limestone, the kind a fugitive hides in), <strong>מְצוּדָתִי</strong> (<em>mĕṣûdātî</em>, "my fortress/stronghold"), <strong>מְפַלְטִי</strong> (<em>mĕphalṭî</em>, "my rescuer/deliverer" — the one who causes to escape), <strong>מָגִנִּי</strong> (<em>māginnî</em>, "my shield" — the small personal shield), <strong>קֶרֶן-יִשְׁעִי</strong> (<em>qeren yishʿî</em>, "the horn of my salvation" — the raised animal horn as the symbol of lifted, victorious strength), and <strong>מִשְׂגַּבִּי</strong> (<em>miśgabbî</em>, "my high tower/stronghold" — a fortified high place). The accumulated images do not build logically; they accumulate intensively, each adding another dimension of divine protective capacity.</p>',
    "3": '<p><strong>מְהֻלָּל אֶקְרָא יְהוָה</strong> (<em>mĕhullāl ʾeqrāʾ YHWH</em>, "I called to the LORD, who is worthy of all praise") — the participle <em>mĕhullāl</em> (pual of <em>hālal</em>: praised, worthy of praise) precedes the verb "I called." The worthiness of the LORD to be praised is stated as the presupposition of prayer: one calls on the one who deserves to be called on. The perfect of confidence follows: "and I am saved (<em>wĕʾiwwāsheaʿ</em>) from my enemies."</p>',
    "4": '<p><strong>חֶבְלֵי-מָוֶת</strong> (<em>ḥeblê-māwet</em>, "cords of death") — <em>ḥebel</em> can mean either "cord/rope" or "birth-pang/anguish" (the same consonants, different vocalization). The context (wrapping around, entangling) points to the "cord" sense, though the birth-pang connotation adds a layer: the death-convulsions that seized him. <strong>נַחֲלֵי בְלִיַּעַל</strong> (<em>naḥălê bĕliyaʿal</em>, "floods of chaos/destruction") — <em>bĕliyaʿal</em> literally means "without profit/worth"; as a cosmic term it represents destructive, anti-order forces (2 Sam 22:5 parallel: "floods of ungodliness"). The imagery merges physical danger with cosmic chaos.</p>',
    "5": '<p><strong>חֶבְלֵי שְׁאוֹל</strong> (<em>ḥeblê shĕʾôl</em>, "ropes of Sheol") — the realm of the dead personified as an active snare-setter. <strong>מוֹקְשֵׁי מָוֶת</strong> (<em>môqĕshê māwet</em>, "snares of death") — <em>môqēsh</em>: a trap or snare for birds; death as a hunter laying traps. The four images of vv4-5 are parallel pairs: cords/ropes and floods/snares, building the picture of inescapable entrapment in mortal danger.</p>',
    "6": '<p><strong>בַּצַּר-לִי אֶקְרָא יְהוָה</strong> (<em>baṣṣar-lî ʾeqrāʾ YHWH</em>, "In my distress I called to the LORD") — the same <em>ṣar</em> (tight place/distress) as Ps 4:1; prayer from within the constriction. <strong>מֵהֵיכָלוֹ יִשְׁמַע קוֹלִי</strong> (<em>mêhêkālô yishmaʿ qôlî</em>, "From his temple he heard my voice") — the cry that rose from the tight earthly space is heard in the heavenly temple (<em>hêkāl</em> = palace/temple). <strong>שַׁוְעָתִי לְפָנָיו תָּבוֹא בְאָזְנָיו</strong> (<em>shawyʿātî lĕpānāyw tābôʾ bĕʾāznāyw</em>) — "my cry came before him into his ears": the two-stage movement (before his face, then into his ears) suggests deliberate hearing, not accidental reception.</p>',
    "7": '<p>The theophany begins. <strong>וַתִּגְעַשׁ וַתִּרְעַשׁ הָאָרֶץ</strong> (<em>wattīgʿash wattirʿash hāʾāreṣ</em>, "The earth shook and trembled") — two verbs for earth-movement: <em>gāʿash</em> (to quake, storm) and <em>rāʿash</em> (to shake, tremble). Both are used in theophanic contexts (Isa 24:19-20). <strong>כִּי-חָרָה לוֹ</strong> (<em>kî-ḥārāh lô</em>, "for he was angry") — literally "for it burned to him" — <em>ḥārāh</em> uses the burning metaphor for divine anger (cf. Ps 2:5). The earth\'s convulsion is the response to divine wrath, not an independent seismic event.</p>',
    "8": '<p><strong>עָלָה עָשָׁן בְּאַפּוֹ</strong> (<em>ʿālāh ʿāshān bĕʾappô</em>, "Smoke poured from his nostrils") — the anthropomorphism is striking: smoke rises from the divine nose/anger (<em>ʾap</em> = nostril/anger). The imagery draws on volcano imagery and on the Sinai theophany (Exod 19:18: "Mount Sinai was covered with smoke, for the LORD descended on it in fire"). <strong>וְאֵשׁ מִפִּיו תֹּאכֵל</strong> (<em>wĕʾêsh mippîw tōʾkel</em>, "consuming fire from his mouth") — divine speech as fire. <em>Gāḥālîm</em> (coals/embers) blazing before him: the attendant of divine presence.</p>',
    "9": '<p><strong>וַיֵּט שָׁמַיִם וַיֵּרַד</strong> (<em>wayyêṭ shāmayim wayyêrad</em>, "He bowed the heavens and came down") — the heavens as a fabric that can be bent down (<em>nāṭāh</em>: to stretch out, to incline). The divine descent through bent-down heaven is the theophanic idiom for God entering the human plane. <strong>וַעֲרָפֶל תַּחַת רַגְלָיו</strong> (<em>waʿărāpel taḥat raglāyw</em>, "dark cloud under his feet") — <em>ʿărāpel</em> is the thick, impenetrable darkness associated with divine presence at Sinai (Deut 4:11; 1 Kgs 8:12). Cloud as the floor the divine warrior walks on.</p>',
    "10": '<p><strong>וַיִּרְכַּב עַל-כְּרוּב וַיָּעֹף</strong> (<em>wayyirkab ʿal-kĕrûb wayyāʿōp</em>, "He mounted a cherub and flew") — the divine chariot imagery: God riding the cherub. The cherubim are the ark-attendants (Exod 25:18-20) and the throne-bearers of the divine chariot (Ezek 1:5-21). <strong>יִדֶּה עַל-כַּנְפֵי-רוּחַ</strong> (<em>yiddeh ʿal-kanpê-rûaḥ</em>, "he soared on the wings of the wind") — the wind as the vehicle of divine movement, consistent with Ps 104:3-4.</p>',
    "11": '<p><strong>יָשֶׁת חֹשֶׁךְ סִתְרוֹ</strong> (<em>yāshet ḥōshek sitrô</em>, "He made darkness his shelter") — paradox: the God of light (Ps 27:1; 1 John 1:5) conceals himself in darkness (<em>ḥōshek</em>). The divine warrior approaches unseen, in the cloud-darkness that protects his unapproachable holiness. <strong>סְכָּתוֹ סְבִיבוֹתָיו</strong> (<em>sĕkātô sĕbîbôtāyw</em>, "his canopy about him") — <em>sukkāh</em> as divine shelter: the same word for the booths of the Festival of Tabernacles.</p>',
    "12": '<p><strong>מִנֹּגַהּ נֶגְדּוֹ</strong> (<em>minnegah negdô</em>, "From the brightness of his presence") — <em>nōgah</em>: brightness, radiance; even from within the dark cloud, the divine presence radiates outward. The clouds burst forth with <strong>בָּרָד וְגַחֲלֵי-אֵשׁ</strong> (<em>bārād wĕgaḥălê-ʾêsh</em>, "hailstones and coals of fire") — the storm weapons of the divine warrior, inverting the expected: the hidden dark cloud does not merely conceal but actively discharges judgment.</p>',
    "13": '<p><strong>וְעֶלְיוֹן יִתֵּן קֹלוֹ</strong> (<em>wĕʿelyôn yittên qōlô</em>, "the Most High raised his voice") — thunder as divine speech. <em>Qôl YHWH</em> (voice of the LORD) is the thunder motif developed fully in Ps 29. The title <em>ʿElyôn</em> (Most High) is the Canaanite divine title absorbed into Israelite theology — used here alongside YHWH, declaring that the Most High God and the covenantal LORD are one.</p>',
    "14": '<p><strong>וַיִּשְׁלַח חִצָּיו וַיְפִיצֵם</strong> (<em>wayyishlah ḥiṣṣāyw wayyĕpîṣêm</em>, "He shot his arrows and scattered them") — lightning as divine arrows. The imagery maps onto the Canaanite storm-god Baal who wielded lightning-weapons, but here repurposed entirely for YHWH\'s combat on behalf of his servant. The enemies scattered by divine lightning are not the cosmic enemies but David\'s historical opponents, showing that cosmic theophanic power is deployed for concrete human rescue.</p>',
    "15": '<p><strong>וַיִּגָּלוּ אֲפִיקֵי מַיִם</strong> (<em>wayyiggālû ʾăpîqê māyim</em>, "The channels of the sea were exposed") — at the divine rebuke, the sea retreats and its underwater channels are laid bare. This echoes the Sea of Reeds: the OT consistently uses the Exodus sea-crossing as the type of divine warrior rescue. <strong>מִגַּעֲרָתְךָ יְהוָה</strong> (<em>migaʿărātĕkā YHWH</em>, "at your rebuke, O LORD") — <em>gĕʿārāh</em> (rebuke, scolding): the sea retreats not from force but from the divine word of rebuke — the same word used in Ps 104:7 for the waters fleeing at creation.</p>',
    "16": '<p><strong>יִשְׁלַח מִמָּרוֹם יִקָּחֵנִי</strong> (<em>yishlah mimmārôm yiqqāḥênî</em>, "He reached down from on high and took hold of me") — the rescue is initiated entirely from above. <em>Mārom</em> (height, the high place) is God\'s position; from there he sends and takes (<em>lāqaḥ</em>: to take, seize, receive). <strong>מִמַּיִם רַבִּים</strong> (<em>mimmaym rabbîm</em>, "from deep waters") — the many/great waters as the chaos-force from which rescue is made; the same waters exposed in v15 are the peril from which the Psalmist is drawn. The image mirrors the infant Moses drawn from the Nile (<em>māshāh</em>, Exod 2:10 — "because I drew him out of the water").</p>',
    "17": '<p><strong>מֵאֹיְבִי עָז</strong> (<em>mêʾōyĕbî ʿāz</em>, "from my powerful enemy") — <em>ʿāz</em> (strong, mighty): the enemy is not merely hostile but powerful, genuinely stronger than the Psalmist (v17b: "for they were stronger than I was"). The admission of inferiority makes the rescue more remarkable — not a story of triumph by superior David, but of weak David rescued by the omnipotent LORD.</p>',
    "18": '<p><strong>יְקַדְּמוּנִי בְיוֹם-אֵידִי</strong> (<em>yĕqaddĕmûnî bĕyôm-ʾêdî</em>, "They confronted me in the day of my disaster") — <em>qādham</em> (piel): to meet/confront (with hostile intent). <em>ʾÊd</em> (calamity, disaster): the word for appointed doom/misfortune — the day when everything was against him. <strong>וַיְהִי יְהוָה לְמִשְׁעָן לִי</strong> (<em>wayhî YHWH lĕmishʿān lî</em>, "but the LORD was my support") — <em>mishʿān</em>: a staff to lean on, a prop. God as the physical support when the Psalmist could not stand on his own.</p>',
    "19": '<p><strong>וַיֹּצִיאֵנִי לַמֶּרְחָב</strong> (<em>wayyôṣîʾênî lammerhāb</em>, "He brought me out into an open place") — the same spatial metaphor as Ps 4:1 (<em>hirchabātā</em>, "you enlarged me"): salvation as movement from the tight place (<em>ṣar</em>) to wide-open space (<em>merehāb</em>). <strong>כִּי חָפֵץ בִּי</strong> (<em>kî ḥāpēṣ bî</em>, "because he was pleased with me") — the reason for rescue: divine delight/desire (<em>ḥāpēṣ</em>). Not David\'s merit but the divine pleasure as the ground of rescue — the same word used in Ps 5:4 (God does not delight in wickedness) deployed in its positive form.</p>',
    "20": '<p><strong>יִגְמְלֵנִי יְהוָה כְּצִדְקִי</strong> (<em>yigmĕlênî YHWH kĕṣidqî</em>, "The LORD rewarded me according to my righteousness") — the theme of righteous vindication: <em>gāmal</em> (to repay, to deal out according to). <em>Ṣedeq</em> (righteousness) and <em>bōr yādāyw</em> (cleanness of hands) are the covenantal integrity that David claims — not sinless perfection but covenant faithfulness. The specific righteousness claimed in vv20-24 is not absolute but relational: faithfulness to the covenant relationship.</p>',
    "21": '<p><strong>שָׁמַרְתִּי דַּרְכֵי יְהוָה</strong> (<em>shāmartî darkê YHWH</em>, "I have kept to the LORD\'s ways") — <em>shāmar</em>: to keep, guard, observe (the same word used for the cherubim guarding the garden, Gen 3:24, and for keeping the commandments). The claim is of faithfulness to the covenantal path, not of personal superiority. <strong>לֹא-רָשַׁעְתִּי מֵאֱלֹהָי</strong> (<em>lōʾ-rāshaʿtî mêʾĕlōhāy</em>, "I have not turned away from my God in rebellion") — <em>rāshaʿ</em>: to act wickedly, to be in the wrong. The negative formulation: no deliberate departure.</p>',
    "22": '<p><strong>כִּי כָּל-מִשְׁפָּטָיו לְנֶגְדִּי</strong> (<em>kî kol-mishpāṭāyw lĕnegdî</em>, "All his rules were set before me") — <em>mishpāṭ</em> (judgment/rule/ordinance) as the standard placed before the eyes. <em>Lĕnegdî</em>: before me, in my sight — the image of the covenantal instruction as a constant visual reference. <strong>חֻקֹּתָיו לֹא-אָסִיר מֶנִּי</strong> (<em>ḥuqqōtāyw lōʾ-ʾāsîr mennî</em>, "I did not set aside his statutes") — <em>ḥōq</em> (statute/ordinance) in contrast to <em>mishpāṭ</em>: the fixed decrees vs the case-by-case judgments.</p>',
    "23": '<p><strong>וָאֶהְיֶה תָמִים עִמּוֹ</strong> (<em>wāʾehyeh tāmîm ʿimmô</em>, "I was blameless before him") — <em>tāmîm</em>: unblemished, whole, without defect — the same word used for the sacrificial animal that must be without blemish (Exod 12:5; Lev 1:3). The Psalmist claims to have been before God with the quality of a valid offering. <strong>וָאֶשְׁתַּמֵּר מֵעֲוֹנִי</strong> (<em>wāʾeshtammêr mêʿăwōnî</em>, "I kept myself from wrongdoing") — hithpael reflexive of <em>shāmar</em>: actively guarding oneself from one\'s own potential iniquity (<em>ʿāwôn</em>).</p>',
    "24": '<p>The repetition of v20\'s language: <strong>כְּצִדְקִי</strong> (<em>kĕṣidqî</em>, "according to my righteousness") and <strong>כְּבֹר יָדַי</strong> (<em>kĕbōr yādāy</em>, "according to the cleanness of my hands") in God\'s sight (<em>לְנֶגֶד עֵינָיו</em>). The claim of vv20-24 forms a unit bounded by these matching formulas, with the specific evidences of faithfulness in vv21-23 as the middle section.</p>',
    "25": '<p><strong>עִם-חָסִיד תִּתְחַסָּד</strong> (<em>ʿim-ḥāsîd titḥassād</em>, "To the faithful you show yourself faithful") — the divine mirror principle: each verb is a niphal or hithpael reflexive showing God "reflecting back" the character of the one approaching him. The pattern is: <em>ḥāsîd</em> (faithful/loyal one) → <em>titḥassād</em> (you act as the faithful/loyal one toward them). Three pairs follow:</p><p>v25: faithful/loyal (<em>ḥāsîd → titḥassād</em>) — v25b: blameless (<em>tāmîm → tittammām</em>) — v26a: pure (<em>bārûr → tittabbār</em>) — v26b: devious/crooked (<em>ʿiqqêsh → tittappe.l</em>, "you show yourself cunning/twisting"). The final pair is the reversal: with the crooked, God acts according to their crookedness — not by becoming unjust, but because justice to the unjust has the appearance of cunning from their perspective.</p>',
    "26": '<p><strong>וְעִם-עִקֵּשׁ תִּתְפַּתָּל</strong> (<em>wĕʿim-ʿiqqêsh tittapattāl</em>, "but to the devious you show yourself cunning") — <em>ʿiqqêsh</em>: perverse, twisted (from <em>ʿāqash</em>, to twist). <em>Tittapattāl</em> (hithpael of <em>pātal</em>): to twist, wrestle, be twisted. The reciprocity is not that God becomes devious but that his consistency in pursuing justice "looks like" cunning or resistance to those who are crooked. The divine way is single; its appearance differs depending on the orientation of the one encountering it.</p>',
    "27": '<p><strong>כִּי-אַתָּה עַם-עָנִי תוֹשִׁיעַ</strong> (<em>kî-ʾattāh ʿam-ʿānî tôshîaʿ</em>, "For you save an afflicted people") — <em>ʿānî</em>: poor, afflicted, humble — the recipient of divine salvation is specifically the one without resources or pretension. <strong>וְעֵינַיִם רָמוֹת תַּשְׁפִּיל</strong> (<em>wĕʿênayim rāmôt tashpîl</em>, "but proud eyes you humble") — <em>rāmôt</em>: raised, lifted up; <em>shāpal</em> (hiphil): to bring low. The reversal is consistent: the humble are lifted (v19: to the open place) and the proud are brought down.</p>',
    "28": '<p><strong>כִּי-אַתָּה תָּאִיר נֵרִי</strong> (<em>kî-ʾattāh tāʾîr nêrî</em>, "you light my lamp") — <em>nêr</em>: lamp, light; <em>ʾûr</em> (hiphil: to cause to shine, to light). The lamp as the symbol of continuing life and divine favor (1 Kgs 11:36: "I will give him one tribe, so that my servant David may always have a lamp before me in Jerusalem"). <strong>יְהוָה אֱלֹהַי יַגִּיהַּ חָשְׁכִּי</strong> (<em>YHWH ʾĕlōhay yagîah ḥāshkî</em>, "the LORD my God brightens my darkness") — <em>nāgah</em> (hiphil: to cause to shine). The darkness (danger, defeat, despair) becomes light through divine illumination — not the removal of the dark situation but the illumination within it.</p>',
    "29": '<p><strong>כִּי בְךָ אָרֻץ גְּדוּד</strong> (<em>kî bĕkā ʾāruṣ gĕdûd</em>, "For by your help I can charge against a raiding party") — <em>gĕdûd</em>: a raiding band, a marauding troop. <em>Rûṣ</em> (to run, to charge). <strong>וּבֵאלֹהַי אֲדַלֶּג-שׁוּר</strong> (<em>ûbêʾĕlōhay ʾădallēg-shûr</em>, "by my God I can scale a wall") — <em>dālag</em>: to leap/spring; <em>shûr</em>: a wall or enemy stronghold. Both images contrast the Psalmist\'s own limitation with what becomes possible "in God" (<em>bĕkā, bêʾĕlōhay</em>) — the "in Christ" language of Paul has its OT template here.</p>',
    "30": '<p><strong>הָאֵל תָּמִים דַּרְכּוֹ</strong> (<em>hāʾêl tāmîm darkô</em>, "This God — his way is perfect") — <em>tāmîm</em> (perfect/unblemished) applied now to God\'s way rather than David\'s conduct (v23). <strong>אִמְרַת יְהוָה צְרוּפָה</strong> (<em>ʾimrat YHWH ṣĕrûpāh</em>, "the LORD\'s word is refined and true") — <em>ṣārap</em>: to smelt, refine (as gold or silver is refined in fire to remove impurities). The divine word has undergone the refinement process — it is pure without alloy. Ps 12:6 uses the same image for the divine promises.</p>',
    "31": '<p><strong>כִּי מִי אֱלוֹהַ מִבַּלְעֲדֵי יְהוָה</strong> (<em>kî mî ʾĕlôah mibbaleʿădê YHWH</em>, "For who is God besides the LORD?") — the rhetorical question presupposes monolatry at minimum: no other claimant to divinity has the qualities just described. <strong>מִי צוּר זוּלָתִי אֱלֹהֵינוּ</strong> (<em>mî ṣûr zûlātî ʾĕlōhênû</em>, "who is a rock except our God?") — <em>ṣûr</em> (rock as refuge and fortress): the test of a divine claim is whether the one claiming divinity can actually provide the stability and protection the rock-metaphor requires. The exclusive answer: only YHWH.</p>',
    "32": '<p><strong>הָאֵל הַמְאַזְּרֵנִי חָיִל</strong> (<em>hāʾêl hamĕʾazzĕrênî ḥāyil</em>, "It is God who arms me with strength") — <em>ʾāzar</em> (piel: to gird, to clothe with a belt/girdle): the image of equipping for battle by fastening the belt/sash that holds the weapons. <em>Ḥāyil</em>: strength, valor, military might. God as the one who does the arming — the passive recipient of divine equipment. <strong>וַיִּתֵּן תָּמִים דַּרְכִּי</strong> (<em>wayyittên tāmîm darkî</em>, "and makes my way perfect") — <em>tāmîm</em> applied to the Psalmist\'s path: God completes or perfects what was incomplete.</p>',
    "33": '<p><strong>מְשַׁוֶּה רַגְלַי כָּאַיָּלוֹת</strong> (<em>mĕshawweh raglāy kāʾayyālôt</em>, "he makes my feet like the feet of a deer") — <em>shāwāh</em> (piel: to make equal, to level, to set properly); <em>ʾayyālāh</em> (doe, hind — the nimble mountain deer). The feet of the deer that navigate rocky terrain without slipping are the image for divinely-given sure-footedness in difficult circumstances. <strong>עַל בָּמֹתַי יַעֲמִידֵנִי</strong> (<em>ʿal bāmōtay yaʿămîdênî</em>, "sets me securely on the heights") — <em>bāmāh</em>: high place; to stand on the heights is military advantage — commanding ground.</p>',
    "34": '<p><strong>מְלַמֵּד יָדַי לַמִּלְחָמָה</strong> (<em>mĕlammêd yādāy lammilḥāmāh</em>, "he trains my hands for battle") — <em>lāmad</em> (piel: to teach, train — the same root as <em>talmîd</em>, disciple): God as the military trainer who teaches the hands their craft. <strong>וְנִחֲתָה קֶשֶׁת-נְחוּשָׁה זְרֹעֹתָי</strong> (<em>wĕniḥătāh qeshet-nĕḥûshāh zĕrōʿōtāy</em>, "my arms can bend a bow of bronze") — the bronze bow would normally exceed human strength; divine-given capacity enables what is naturally impossible.</p>',
    "35": '<p><strong>וַתִּתֶּן-לִי מָגֵן יִשְׁעֶךָ</strong> (<em>wattitten-lî māgên yishʿekā</em>, "You have given me the shield of your salvation") — the shield is specifically "of your salvation" (<em>yeshûʿâ</em>): protective, yes, but the protection is the product of divine saving activity. <strong>וַעֲנָוַתְךָ תַרְבֵּנִי</strong> (<em>waʿănāwātĕkā tarbênî</em>, "your gentleness made me great") — the key term <em>ʿănāwāh</em>: condescension, humility, gentleness. It is the LORD\'s condescension (<em>ʿānāw</em>: humble/meek) toward the Psalmist that makes him great. This is the paradox at the heart of the psalm: greatness comes not from David\'s power but from divine condescension that stoops to lift.</p>',
    "36": '<p><strong>תַּרְחִיב צַעֲדִי תַחְתָּי</strong> (<em>tarḥîb ṣaʿădî taḥtāy</em>, "You gave wide room for my steps beneath me") — <em>rāḥab</em> (hiphil: to widen/enlarge): the spatial metaphor of salvation as room to move, returning from Ps 4:1 and 18:19. <em>Ṣaʿad</em> (steps, stride) — a wide stride, confident movement. <strong>וְלֹא מָעֲדוּ קַרְסֻלָּי</strong> (<em>wĕlōʾ māʿădû qarsullāy</em>, "my feet did not slip") — <em>māʿad</em>: to slip, to totter; <em>qarsôl</em>: ankle. The ankle as the vulnerable joint of confident movement: divine enlargement of the path prevented the ankle-turning that a tight path would cause.</p>',
    "37": '<p><strong>אֶרְדֹּף אוֹיְבַי וְאַשִּׂיגֵם</strong> (<em>ʾerdōp ʾôyĕbay wĕʾassîgêm</em>, "I pursued my enemies and overtook them") — the pursuit language reverses vv4-5: David was the hunted one, now he pursues. <em>Rādap</em> (to pursue, chase) and <em>nāśag</em> (to overtake, reach): the decisive engagement. <strong>וְלֹא-אָשׁוּב עַד-כַּלּוֹתָם</strong> (<em>wĕlōʾ-āshûv ʿad-kallôtām</em>, "and did not turn back until they were finished") — <em>kālāh</em> (to complete/finish/destroy): no premature withdrawal; the pursuit continues to completion.</p>',
    "38": '<p><strong>אֶמְחָצֵם וְלֹא-יֻכְלוּ קוּם</strong> (<em>ʾemḥāṣêm wĕlōʾ-yûklû qûm</em>, "I struck them down so that they could not rise") — <em>māḥaṣ</em>: to shatter, to smite decisively. The inability to rise after being struck is the language of permanent defeat. <strong>יִפְּלוּ תַּחַת רַגְלָי</strong> (<em>yippĕlû taḥat raglāy</em>, "they fell under my feet") — the posture of complete submission: under the feet, the position of the vanquished before the victor (cf. Ps 110:1; Josh 10:24).</p>',
    "39": '<p><strong>וַתְּאַזְּרֵנִי חַיִל לַמִּלְחָמָה</strong> (<em>watĕʾazzĕrênî ḥayil lammilḥāmāh</em>, "For you armed me with strength for the battle") — resuming the divine-equipping motif of v32; the battle\'s outcome is not David\'s achievement but the product of divine arming. <strong>תַּכְרִיעַ קָמַי תַּחְתָּי</strong> (<em>takrîaʿ qāmay taḥtāy</em>, "you brought down under me those who rose against me") — <em>kāraʿ</em> (hiphil: to cause to kneel/bow down): God as the one who brings the adversaries to their knees beneath David.</p>',
    "40": '<p><strong>וְאֹיְבַי נָתַתָּה לִּי עֹרֶף</strong> (<em>wĕʾōyĕbay nātattāh llî ʿōrep</em>, "You made my enemies turn their backs in retreat") — <em>ʿōrep</em> (back of the neck): to show the back of the neck is to flee in retreat; the enemies are turned to expose their most vulnerable position. <strong>וּמְשַׂנְאַי אַצְמִיתֵם</strong> (<em>ûmĕsanʾay ʾaṣmîtêm</em>, "I destroyed those who hated me") — <em>ṣāmat</em>: to silence, destroy, cut off (rare word; the hiphil indicates causing to be silenced).</p>',
    "41": '<p><strong>יְשַׁוְּעוּ וְאֵין-מוֹשִׁיעַ</strong> (<em>yĕshawwĕʿû wĕʾên-môshîaʿ</em>, "They cried for help, but there was no one to save them") — the enemies\' cry reverses David\'s: he cried (v6) and was heard; they cry and find no <em>môshîaʿ</em> (savior/deliverer). <strong>עַל-יְהוָה וְלֹא עָנָם</strong> (<em>ʿal-YHWH wĕlōʾ ʿānām</em>, "they even cried to the LORD, but he did not answer them") — the contrast is sharp: the same LORD who heard David\'s cry (v6) did not answer their cry. Not arbitrary: they were the enemies of his anointed and had no relational claim on his response.</p>',
    "42": '<p><strong>וְאֶשְׁחָקֵם כְּעָפָר עַל-פְּנֵי-רוּחַ</strong> (<em>wĕʾeshḥāqêm kĕʿāpār ʿal-pĕnê-rûaḥ</em>, "I ground them fine as windblown dust") — <em>shāḥaq</em>: to grind, to pulverize (the same root as fine dust). <em>Kĕʿāpār ʿal-pĕnê-rûaḥ</em>: "like dust on the face of the wind." The contrast with v3 (chaff blown by the wind in Ps 1) is instructive: the enemies become the chaff, scattered by the wind of divine judgment.</p>',
    "43": '<p><strong>תְּפַלְּטֵנִי מֵרִיבֵי עָם</strong> (<em>tĕpalĕṭênî mêrîbê ʿām</em>, "You saved me from conflicts with my own people") — <em>rîb</em>: legal dispute, quarrel; the enemies within the people, not only foreign nations. <strong>תְּשִׂימֵנִי לְרֹאשׁ גּוֹיִם</strong> (<em>tĕsîmênî lĕrōʾsh gôyim</em>, "you made me head of the nations") — the scope of David\'s kingship extends to the nations; the language anticipates the royal universalism of Ps 2:8. Paul cites v49 in this context as the ground for Gentile worship.</p>',
    "44": '<p><strong>לִשְׁמוֹעַ אֹזֶן יִשָּׁמְעוּ-לִי</strong> (<em>lishmoaʿ ʾōzen yishshāmĕʿû-lî</em>, "As soon as they heard of me, they obeyed") — literally "at the hearing of the ear they obeyed me." <em>Shāmaʿ</em> appears three times in this phrase, emphasizing the immediacy and totality of the submission. <strong>בְּנֵי-נֵכָר יְכַחֲשׁוּ-לִי</strong> (<em>bĕnê-nêkār yĕkaḥăshû-lî</em>, "foreigners submitted to me") — <em>kāḥash</em>: to fail, deny, cringe/submit reluctantly; the foreigners\' submission is not voluntary homage but the submission of the defeated.</p>',
    "45": '<p><strong>בְּנֵי-נֵכָר יִבֹּלוּ</strong> (<em>bĕnê-nêkār yibbōlû</em>, "Foreigners lost their courage") — <em>nābēl</em>: to wither, to fade (as a leaf withers); the courage of the foreign peoples wilted. <strong>וְיַחְגְּרוּ מִמִּסְגְּרוֹתָם</strong> (<em>wĕyaḥgĕrû mimmisĕgrôtām</em>, "came out of their fortresses trembling") — <em>ḥāgar</em>: to gird oneself (for movement or battle); <em>misegĕrôt</em>: strongholds, locked places. The irony: they gird themselves to emerge from their fortresses — not in bold battle-readiness but in trembling, forced submission.</p>',
    "46": '<p><strong>חַי-יְהוָה וּבָרוּךְ צוּרִי</strong> (<em>ḥay-YHWH ûbārûk ṣûrî</em>, "The LORD lives! Blessed be my Rock!") — <em>ḥay YHWH</em>: "As the LORD lives!" — an oath formula certifying that what follows is true. But here it also functions as a declaration of divine life in contrast to the dead idols who cannot hear or respond (contrast v41). <em>Bārûk ṣûrî</em>: formal blessing directed toward God, now using <em>bārûk</em> (the formal blessing-word) rather than <em>ʾashrê</em>. <strong>וְיָרוּם אֱלֹהֵי יִשְׁעִי</strong> (<em>wĕyārûm ʾĕlōhê yishʿî</em>, "Exalted be the God of my salvation") — a wish or declaration: may the God of my salvation be lifted high.</p>',
    "47": '<p><strong>הָאֵל הַנֹּתֵן נְקָמוֹת לִי</strong> (<em>hāʾêl hannōtên nĕqāmôt lî</em>, "the God who gives me justice") — <em>nĕqāmāh</em>: vengeance, vindication; the MKT renders it "justice" to capture the sense of setting right what was wrong. <strong>וַיַּדְבֵּר עַמִּים תַּחְתָּי</strong> (<em>wayyaddêr ʿammîm taḥtāy</em>, "subdues peoples under me") — <em>dābar</em> (hiphil?): actually this should be <em>wĕyaddêr</em> from <em>dābar</em> meaning to subdue/bring low; the peoples placed under him.</p>',
    "48": '<p><strong>מְפַלְּטִי מֵאֹיְבָי</strong> (<em>mĕpallĕṭî mêʾōyĕbāy</em>, "who rescued me from my enemies") — the same root <em>pālaṭ</em> from v2 (<em>mĕphalṭî</em>): rescuer. The psalm circles back to the opening cluster of rescue metaphors. <strong>אַף מִן-קָמַי תְּרוֹמְמֵנִי</strong> (<em>ʾap min-qāmay tĕrômĕmênî</em>, "you lifted me above those who rose against me") — <em>rûm</em> (hiphil: to lift up, exalt): the divine lifting is above those who tried to bring down.</p>',
    "49": '<p><strong>עַל-כֵּן אוֹדְךָ בַגּוֹיִם יְהוָה</strong> (<em>ʿal-kên ʾôdĕkā baggôyim YHWH</em>, "Therefore I will give you thanks, O LORD, among the nations") — the climactic thanksgiving. <strong>בַגּוֹיִם</strong> (<em>baggôyim</em>): "among the nations/Gentiles" — the Davidic king\'s testimony extends beyond Israel to the watching Gentile nations. Paul quotes this verse in Rom 15:9 as a proof text that the Scriptures anticipated Gentile worship: "I will praise you among the Gentiles." The Psalm\'s historical statement (David\'s international testimony) becomes the NT\'s foundation for Gentile inclusion in the praise of God.</p>',
    "50": '<p><strong>מַגְדִּיל יְשׁוּעוֹת מַלְכּוֹ</strong> (<em>magdîl yĕshûʿôt malkô</em>, "He gives great salvation to his king") — <em>gādal</em> (hiphil participle: causing to be great, magnifying): ongoing activity of magnifying salvations. The plural <em>yĕshûʿôt</em> (salvations) suggests multiple repeated rescues. <strong>וְעֹשֶׂה-חֶסֶד לִמְשִׁיחוֹ לְדָוִד וּלְזַרְעוֹ עַד-עוֹלָם</strong> (<em>wĕʿōseh-ḥesed limshîḥô lĕdāwid ûlĕzarʿô ʿad-ʿôlām</em>, "shows steadfast love to his anointed — to David and his descendants forever") — the <em>ḥesed</em> (covenant loyalty) promised to the <em>māshîaḥ</em> (anointed) extends forever (<em>ʿad-ʿôlām</em>). The psalm closes on the covenant: the Davidic line as the recipient of perpetual divine <em>ḥesed</em>, a promise that points beyond historical David to the eternal Anointed One.</p>',
  },
  "19": {
    "1": '<p><strong>הַשָּׁמַיִם מְסַפְּרִים כְּבוֹד-אֵל</strong> (<em>hashāmayim mĕsappĕrîm kĕbôd-ʾêl</em>, "The heavens declare the glory of God") — the participle <em>mĕsappĕrîm</em> (from <em>sāpar</em>: to count, recount, narrate): an ongoing, unceasing declaration. The heavens are not said to have declared or to eventually declare — they are perpetually in the act of narrating. <strong>וּמַעֲשֵׂה יָדָיו מַגִּיד הָרָקִיעַ</strong> (<em>ûmaʿăśê yādāyw maggîd hārāqîaʿ</em>, "the expanse proclaims his handiwork") — <em>rāqîaʿ</em>: the firmament/expanse (from <em>rāqaʿ</em>, to hammer/beat out thin). The beaten-out sky continually announces (participle) the work of God\'s hands.</p>',
    "2": '<p><strong>יוֹם לְיוֹם יַבִּיעַ אֹמֶר</strong> (<em>yôm lĕyôm yabbiʿa ʾōmer</em>, "Day after day pours out its speech") — <em>nābaʿ</em> (hiphil: to pour out, to bubble up): the image of water welling up from a spring — speech as inexhaustible, effervescent outpouring. <em>ʾŌmer</em>: speech, word (a poetic word). <strong>וְלַיְלָה לְּלַיְלָה יְחַוֶּה-דָּעַת</strong> (<em>wĕlaylāh llĕlaylāh yĕḥawweh-dāʿat</em>, "and night after night reveals knowledge") — <em>ḥāwāh</em> (piel: to show, to tell, to reveal): night declaring what day cannot. The entire calendar — every day, every night — participates in the continuous revelation.</p>',
    "3": '<p><strong>אֵין-אֹמֶר וְאֵין דְּבָרִים</strong> (<em>ʾên-ʾōmer wĕʾên dĕbārîm</em>, "There is no speech, there are no words") — the paradox that defines the whole passage: the declaration of vv1-2 is made in no human language. <em>Bĕlî nishmaʿ qôlām</em>: "without their voice being heard." The communication is real but without the normal medium of communication. This is general revelation: information without human words, encounter without verbal address.</p>',
    "4": '<p><strong>בְּכָל-הָאָרֶץ יָצָא קַוָּם</strong> (<em>bĕkol-hāʾāreṣ yāṣāʾ qawwām</em>, "Yet their proclamation goes out through all the earth") — <em>qaw</em>: a measuring line, a cord; by extension, a line of text or a voice-line. The LXX translates it φθόγγος (sound/voice), which Paul uses in Rom 10:18: "their voice has gone out into all the earth." The silent proclamation nevertheless "goes out" (<em>yāṣāʾ</em>: to go forth, exit) to all the earth. <strong>הַשֶּׁמֶשׁ שָׂם אֹהֶל בָּהֶם</strong> (<em>hashemesh śām ʾōhel bāhem</em>, "In the heavens he has pitched a tent for the sun") — at v4b the Psalm turns to the sun as the supreme example of the heavens\' declaration.</p>',
    "5": '<p><strong>וְהוּא כְּחָתָן יֹצֵא מֵחֻפָּתוֹ</strong> (<em>wĕhûʾ kĕḥātān yōṣêʾ mêḥuppātô</em>, "which rises like a bridegroom leaving his chamber") — <em>ḥātān</em>: bridegroom; <em>ḥuppāh</em>: the bridal chamber. The sun rising is like a bridegroom emerging from the wedding chamber — full of energy, beauty, and anticipation. <strong>יָשִׂישׂ כְּגִבּוֹר לָרוּץ אֹרַח</strong> (<em>yāśîś kĕgibbôr lārûṣ ʾōraḥ</em>, "rejoices like a champion eager to run his course") — <em>gibbôr</em>: hero, mighty man; <em>rûṣ</em>: to run. The sun as an eager athlete who cannot wait to begin his course — joy and strength combined.</p>',
    "6": '<p><strong>מִקְצֵה הַשָּׁמַיִם מוֹצָאוֹ</strong> (<em>miqṣeh hashāmayim môṣāʾô</em>, "Its rising is from one end of the heavens") — the full arc of the sun\'s path described in spatial terms. <strong>וְאֵין נִסְתָּר מֵחַמָּתוֹ</strong> (<em>wĕʾên nistār mêḥammātô</em>, "nothing is hidden from its heat") — <em>nistār</em> (niphal participle: hidden, concealed); <em>ḥammāh</em>: heat, warmth. The universal reach of the sun\'s heat prepares the transition to vv7-9: just as the sun reaches everywhere, so the Torah of the LORD illuminates everything.</p>',
    "7": '<p><strong>תּוֹרַת יְהוָה תְּמִימָה מְשִׁיבַת נָפֶשׁ</strong> (<em>tôrat YHWH tĕmîmāh mĕshîbat nāpesh</em>, "The instruction of the LORD is perfect, reviving the soul") — the first of six <em>attribute + effect</em> pairs describing the divine word. <em>Tôrāh</em> (instruction, as in Ps 1:2); <em>tĕmîmāh</em> (perfect, unblemished — the sacrificial adjective now applied to Torah: it is the word without flaw). <em>Mĕshîbat nāpesh</em>: "restoring/reviving the soul" — <em>shûb</em> (to return/restore): the instruction brings back what has wandered or declined. The image of the word as nourishment that restores strength.</p>',
    "8": '<p><strong>פִּקּוּדֵי יְהוָה יְשָׁרִים</strong> (<em>piqqûdê YHWH yĕshārîm</em>, "The precepts of the LORD are right") — <em>piqqûd</em>: what is entrusted for oversight, a commanded charge (plural <em>piqqûdîm</em>). <em>Yāshar</em> (right, straight): the precepts go in a straight line, without deviation. <em>Mĕsamĕḥê lêb</em>: "making the heart rejoice" — the straight path produces the joy of knowing one\'s feet are rightly placed. <strong>מִצְוַת יְהוָה בָּרָה</strong> (<em>miṣwat YHWH bārāh</em>, "the commandment of the LORD is radiant") — <em>bārāh</em>: pure, bright, clear; <em>mĕʾîrat ʿênāyim</em>: "enlightening the eyes." The singular <em>miṣwāh</em> (commandment) as the totality of divine command — clear and eye-opening.</p>',
    "9": '<p><strong>יִרְאַת יְהוָה טְהוֹרָה</strong> (<em>yirʾat YHWH ṭĕhôrāh</em>, "The fear of the LORD is pure") — the sixth term in the series is not a document (<em>tôrāh, ʿêdût, piqqûdîm, miṣwat, mishpĕṭê</em>) but an attitude: the fear of the LORD itself. <em>Ṭāhôr</em>: ritually and morally clean, pure (the priestly purity vocabulary). <em>ʿOmedet lāʿad</em>: "enduring forever" — the fear of the LORD is not a passing emotion but the stable orientation that persists. <strong>מִשְׁפְּטֵי-יְהוָה אֱמֶת</strong> (<em>mishpĕṭê-YHWH ʾĕmet</em>, "the judgments of the LORD are true") — <em>ʾĕmet</em> (truth, faithfulness, reliability): the judgments correspond to reality.</p>',
    "10": '<p><strong>הַנֶּחֱמָדִים מִזָּהָב</strong> (<em>hanneḥĕmādîm mizzāhāb</em>, "They are more desirable than gold") — <em>nāḥmad</em> (niphal participle: desired, coveted — from the same root as the tenth commandment\'s "do not covet"). The divine words are desirable in the same way that gold and honey are desirable. <strong>וּמֶתֶק מִדְּבַשׁ וְנֹפֶת צוּפִים</strong> (<em>ûmeteq mĕkdbash wĕnōpet ṣûpîm</em>, "sweeter than honey, than honey dripping from the comb") — <em>nōpet</em>: the dripping of a honeycomb, the finest honey; <em>ṣûpîm</em>: flowing, dripping honeycombs. The sweetness is the most refined and abundant form available.</p>',
    "11": '<p><strong>גַּם-עַבְדְּךָ נִזְהָר בָּהֶם</strong> (<em>gam-ʿabdĕkā nizhar bāhem</em>, "your servant is warned by them") — <em>zāhar</em> (niphal: to be warned, to be enlightened by a warning light — from a root meaning to shine): warned as one is warned by a light that reveals a danger ahead. <strong>בְּשָׁמְרָם עֵקֶב רָב</strong> (<em>bĕshomrām ʿêqeb rāb</em>, "in keeping them there is great reward") — <em>ʿêqeb</em>: consequence, result, reward (literally "at the heel" — what follows behind). Keeping the word has a heel-trail of great reward.</p>',
    "12": '<p><strong>שְׁגִיאוֹת מִי-יָבִין</strong> (<em>shĕgîʾôt mî-yābîn</em>, "Who can understand his own errors?") — <em>shĕgîʾāh</em>: an error, a mistake, a wandering from the path (from <em>shāgāh</em>: to wander/err; the same root as <em>shiggāyôn</em> in Ps 7:1). The rhetorical question implies the answer: no one fully understands their own errors. <strong>מִנִּסְתָּרוֹת נַקֵּנִי</strong> (<em>minnestārôt naqqênî</em>, "Cleanse me from sins I cannot see") — <em>nistarôt</em>: hidden things, secret faults — not morally hidden sins (deliberate concealment) but sins that are invisible to the sinner because of their own moral blind spots. <em>Nāqāh</em> (piel: to cleanse, acquit).</p>',
    "13": '<p><strong>גַּם מִזֵּדִים חֲשֹׂךְ עַבְדֶּךָ</strong> (<em>gam mizzêdîm ḥăśōk ʿabdekā</em>, "Keep your servant also from willful sins") — <em>zêdîm</em>: the arrogant, presumptuous ones; from <em>zûd</em> (to boil up, to be insolent). The contrast with <em>nistarôt</em> is crucial: v12 covers unconscious errors; v13 covers deliberate, willful transgressions. This exactly maps onto the Num 15 categories of <em>bishgāgāh</em> (by mistake) vs <em>bĕyad rāmāh</em> (with a high/defiant hand) sin — the former has a sacrificial remedy; the latter does not. <strong>אָז אֵיתָם</strong> (<em>ʾāz ʾêtam</em>, "Then I will be blameless") — "then" (<em>ʾāz</em>) indicates the consequence: kept from willful sin, the Psalmist would attain the blamelessness of Ps 18:23.</p>',
    "14": '<p><strong>יִהְיוּ לְרָצוֹן אִמְרֵי-פִי</strong> (<em>yihyû lĕrāṣôn ʾimrê-pî</em>, "May the words of my mouth be pleasing in your sight") — <em>rāṣôn</em>: pleasure, delight, acceptance (the same root as <em>rāṣāh</em> used in Ps 18:19 — "he was pleased with me"). The prayer is that speech and meditation (<em>hĕgyôn libbî</em> — the inward <em>hāgāh</em> murmuring of Ps 1:2) be acceptable before God. <strong>צוּרִי וְגֹאֲלִי</strong> (<em>ṣûrî wĕgōʾălî</em>, "my rock and my redeemer") — the two closing titles: <em>ṣûr</em> (rock, as in Ps 18) and <em>gōʾêl</em> (kinsman-redeemer — the one who has the legal right and relational obligation to buy back what has been lost). The psalm closes with a prayer to the one who is both immovable foundation and closest redeeming kinsman.</p>',
  },
  "20": {
    "1": '<p><strong>יַעַנְךָ יְהוָה בְּיוֹם צָרָה</strong> (<em>yaʿankā YHWH bĕyôm ṣārāh</em>, "May the LORD answer you in your day of trouble!") — the jussive <em>yaʿankā</em> (may he answer you) opens a series of blessings for the king before battle. The congregation speaks in the third person about the king and the LORD. <em>Yôm ṣārāh</em>: the day of tight distress (same root as <em>ṣar</em>, Ps 4:1; 18:6). <strong>יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב</strong> (<em>yĕśaggĕbkā shêm ʾĕlōhê yaʿăqōb</em>, "May the name of the God of Jacob set you on high!") — <em>śāgab</em> (piel: to set on high, to make inaccessible/safe): the name of the God of Jacob as the one who lifts up to safety. The title "God of Jacob" invokes the patriarchal covenant.</p>',
    "2": '<p><strong>יִשְׁלַח-עֶזְרְךָ מִקֹּדֶשׁ</strong> (<em>yishlah-ʿezrĕkā miqqōdesh</em>, "May he send you help from his sanctuary") — the divine help is dispatched (<em>shālaḥ</em>: to send, to release) from the sanctuary (<em>qōdesh</em>): the heavenly temple, the source of all aid. <strong>וּמִצִּיּוֹן יִסְעָדֶךָּ</strong> (<em>ûmîṣṣiyyôn yisʿādekā</em>, "support you from Zion!") — <em>sāʿad</em>: to support, sustain (as one supports another who is about to fall); Zion as the earthly location of divine presence.</p>',
    "3": '<p><strong>יִזְכֹּר כָּל-מִנְחֹתֶיךָ</strong> (<em>yizkōr kol-minḥōtêkā</em>, "May he remember all your offerings") — <em>zākar</em>: to remember with active concern, to call to mind and act on. The <em>minḥāh</em> (grain offering) and <em>ʿôlāh</em> (burnt offering — what goes up in smoke entirely) as the worshiping acts that precede battle. The prayer is that God accepts and responds to these acts of worship. <em>Selāh</em> marks the pause after the first unit of blessing.</p>',
    "4": '<p><strong>יִתֶּן-לְךָ כִלְבָבֶךָ</strong> (<em>yittĕn-lĕkā kilbābĕkā</em>, "May he grant you your heart\'s desire") — the prayer for divine alignment with the king\'s desires — not a blank check but the prayer that the king\'s desires are already aligned with God\'s will (implied by the preceding religious context). <strong>וְכָל-עֲצָתְךָ יְמַלֵּא</strong> (<em>wĕkol-ʿăṣātĕkā yĕmallêʾ</em>, "and fulfill all your plans!") — <em>ʿēṣāh</em>: counsel, plan, strategy. <em>Mālêʾ</em> (piel: to fill, to fulfill, to bring to completion).</p>',
    "5": '<p><strong>נְרַנְּנָה בִּישׁוּעָתֶךָ</strong> (<em>nĕrannĕnāh bîshûʿātekā</em>, "May we shout for joy at your victory") — <em>rānan</em>: to shout, to ring out (a ringing cry of joy or lamentation — context determines which); here the shout of victory. The congregation anticipates celebrating the king\'s salvation as their own. <strong>וּבְשֵׁם-אֱלֹהֵינוּ נִדְגֹּל</strong> (<em>ûbĕshêm-ʾĕlōhênû nidgōl</em>, "in the name of our God raise our banners!") — <em>dāgal</em>: to raise a banner/standard; the military banner as the visible rallying point. Raising banners in God\'s name rather than in the king\'s name or the nation\'s.</p>',
    "6": '<p><strong>עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יְהוָה מְשִׁיחוֹ</strong> (<em>ʿattāh yādaʿtî kî hôshîaʿ YHWH mĕshîḥô</em>, "Now I know that the LORD saves his anointed one") — the singular first person breaks in: "now I know." Whether a priest, prophet, or the king himself speaking, this is a declaration of certainty. <em>Yādaʿ</em> (to know): experiential, relational knowing. <strong>יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ</strong> (<em>yaʿănêhû mishshĕmê qodshô</em>, "he answers him from his holy heaven") — the answer comes from the holy heavens (<em>shĕmê qodshô</em>: heavens of his holiness), not from earthly resources. <em>Bighĕbûrôt yêshaʿ yĕmînô</em>: "by the saving power (<em>gĕbûrôt</em>, mighty acts/power) of his right hand."</p>',
    "7": '<p><strong>אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים</strong> (<em>ʾêlleh bārekeb wĕʾêlleh bassûsîm</em>, "Some boast in chariots and some in horses") — the contrast is absolute: the military establishment of Israel\'s neighbors depends on chariot-forces and cavalry (the dominant military technology of the ancient Near East). <strong>וַאֲנַחְנוּ בְּשֵׁם-יְהוָה אֱלֹהֵינוּ נַזְכִּיר</strong> (<em>waʾănaḥnû bĕshêm-YHWH ʾĕlōhênû nazkîr</em>, "but we will boast in the name of the LORD our God") — <em>zākar</em> (hiphil: to make remembered, to invoke, to call to mind): not merely "mention" but actively invoke the name as the basis of confidence.</p>',
    "8": '<p><strong>הֵמָּה כָּרְעוּ וְנָפָלוּ</strong> (<em>hêmmāh kāreʿû wĕnāpālû</em>, "They collapse and fall") — the confident perfect tense of certainty: it is as if already accomplished. Those who trust chariots (<em>kāraʿ</em>: bow, bend the knee — in defeat; <em>nāpal</em>: fall) will fail. <strong>וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד</strong> (<em>waʾănaḥnû qamnû wannitʿôdād</em>, "but we rise and stand firm") — <em>qûm</em> (to rise) and <em>ʿûd</em> (hithpael: to strengthen oneself, to rally): those who trust in the divine name rise and are strengthened.</p>',
    "9": '<p><strong>יְהוָה הוֹשִׁיעָה</strong> (<em>YHWH hôshîʿāh</em>, "LORD, give victory to the king!") — the hiphil imperative of <em>yāshaʿ</em>: save! The abrupt imperative after vv6-8\'s confident declarations is the cry that gives voice to the underlying dependence. The psalm ends as a prayer rather than a triumphant statement: confidence is founded on divine saving, so the final word is a request for exactly that. <strong>הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם-קָרְאֵנוּ</strong> (<em>hammelekh yaʿănênû bĕyôm-qārĕʾênû</em>, "Answer us when we call") — the MT is difficult: "the King will answer us in the day we call" — may be a statement of confidence rather than a petition, reading <em>yaʿănênû</em> as a declarative rather than a jussive.</p>',
  },
  "21": {
    "1": '<p><strong>יִשְׂמַח-מֶלֶךְ בְּעֻזְּךָ יְהוָה</strong> (<em>yismah-melekh bĕʿuzzĕkā YHWH</em>, "The king rejoices in your strength, LORD") — the royal psalm of thanksgiving following the victory anticipated in Ps 20. The king\'s rejoicing is grounded in <em>ʿōz</em> (strength): the same word as Ps 18:1 (<em>ḥizqî</em>, "my strength") but now the divine strength specifically. <strong>וּבִישׁוּעָתְךָ מַה-יָּגִיל מְאֹד</strong> (<em>ûbîshûʿātĕkā māh-yāgîl mĕʾōd</em>, "in your salvation how greatly he exults!") — <em>gîl</em>: intense, even physical rejoicing (Ps 19:5 used it of the sun\'s running); <em>mĕʾōd</em>: greatly, exceedingly.</p>',
    "2": '<p><strong>תַּאֲוַת לִבּוֹ נָתַתָּה לּוֹ</strong> (<em>taʾăwat libbô nātattāh llô</em>, "You have given him his heart\'s desire") — the same concept prayed for in Ps 20:4 is now reported as granted. <em>Taʾăwāh</em>: desire, longing — the deep wanting of the heart. <em>Nātan</em> (perfect: given, completed act). <strong>וַאֲרֶשֶׁת שְׂפָתָיו בַּל-מָנַעְתָּ</strong> (<em>waʾăreshet śĕpātāyw bal-mānaʿtā</em>, "have not withheld what his lips requested") — <em>ʾăreshet</em>: request, what the lips petition. <em>Mānaʿ</em> (to withhold, deny): not withheld. The paired statement: given what he desired, not withheld what he requested. <em>Selāh</em>.</p>',
    "3": '<p><strong>כִּי-תְקַדְּמֶנּוּ בִּרְכוֹת טוֹב</strong> (<em>kî-tĕqaddĕmennû birĕkôt ṭôb</em>, "For you meet him with blessings of goodness") — <em>qādam</em> (piel: to come before, to meet in advance): God goes ahead of the king and meets him with blessings. <em>Birĕkôt ṭôb</em>: blessings of goodness/prosperity — not a single blessing but multiple. <strong>תָּשִׁית לְרֹאשׁוֹ עֲטֶרֶת פָּז</strong> (<em>tāshît lĕrōʾshô ʿăṭeret paz</em>, "you set a crown of finest gold upon his head") — <em>ʿăṭāret</em>: a crown, a wreath of honor; <em>paz</em>: refined gold, the purest gold. The divine coronation: God himself places the finest crown on the king\'s head, not the human coronation ceremony alone.</p>',
    "4": '<p><strong>חַיִּים שָׁאַל מִמְּךָ נָתַתָּה לּוֹ</strong> (<em>ḥayyîm shāʾal mimmĕkā nātattāh llô</em>, "He asked you for life, and you gave it to him") — the king\'s petition for life (<em>ḥayyîm</em>, plural of fullness) was answered. <strong>אֹרֶךְ יָמִים עוֹלָם וָעֶד</strong> (<em>ʾōrek yāmîm ʿôlām wāʿed</em>, "length of days forever and ever") — the phrase <em>ʿôlām wāʿed</em>: forever and continuing — the most emphatic temporal expression. For a historical king, this is the prayer for dynasty; for the Messianic king, it is literal eternal life. Heb 1:8 cites the parallel Ps 45:6 ("your throne, O God, will last forever and ever") for Christ; Ps 21:4\'s language functions in the same register for NT readers.</p>',
    "5": '<p><strong>גָּדוֹל כְּבוֹדוֹ בִּישׁוּעָתֶךָ</strong> (<em>gādôl kĕbôdô bîshûʿātekā</em>, "Through your salvation his glory is great") — the king\'s glory (<em>kābôd</em>: weight, honor, splendor) is great specifically "in your salvation" — the salvation is the source of the glory, not the king\'s own achievement. <strong>הוֹד-וְהָדָר תְּשַׁוֶּה עָלָיו</strong> (<em>hôd-wĕhādār tĕshawweh ʿālāyw</em>, "you have bestowed splendor and majesty upon him") — <em>hôd</em> (splendor, the divine majesty vocabulary of Ps 8:1) and <em>hādār</em> (majesty, beauty) — the two terms of divine glory now conferred on the human king. The transfer of divine glory-vocabulary to the royal figure is one of the foundations of Messianic expectation.</p>',
    "6": '<p><strong>כִּי-תְשִׁיתֵהוּ בְרָכוֹת לָעַד</strong> (<em>kî-tĕshîtêhû bĕrākôt lāʿad</em>, "For you make him most blessed forever") — <em>shît</em> (to place, set, make): God makes the king into a source of blessing (<em>bĕrākôt</em>: blessings, the formal benedictions). <em>Lāʿad</em>: for eternity, perpetually. <strong>תְּחַדֵּהוּ בְשִׂמְחָה אֶת-פָּנֶיךָ</strong> (<em>tĕḥaddêhû bĕśimḥāh ʾet-pānêkā</em>, "you fill him with gladness in your presence") — <em>ḥādāh</em> (piel: to make glad, to fill with joy); <em>pānêkā</em>: your face/presence. Joy in the divine presence as the supreme royal blessing.</p>',
    "7": '<p><strong>כִּי-הַמֶּלֶךְ בֹּטֵחַ בַּיהוָה</strong> (<em>kî-hammelekh bōṭêaḥ baYHWH</em>, "For the king trusts in the LORD") — <em>bāṭaḥ</em>: to trust, to feel secure (the physical sense of leaning against something solid). The participle: ongoing, habitual trust. <strong>וּבְחֶסֶד עֶלְיוֹן בַּל-יִמּוֹט</strong> (<em>ûbĕḥesed ʿelyôn bal-yimmôṭ</em>, "through the steadfast love of the Most High he will not be shaken") — <em>ḥesed ʿElyôn</em>: the covenant loyalty of the Most High (the highest divine title). <em>Māṭ</em> (niphal: to totter, to be shaken): the king who rests in divine <em>ḥesed</em> cannot be toppled. Ps 125:1 used the same image for the immovable mountain of Zion.</p>',
    "8": '<p><strong>תִּמְצָא יָדְךָ לְכָל-אֹיְבֶיךָ</strong> (<em>timṣāʾ yādĕkā lĕkol-ʾōyĕbêkā</em>, "Your hand will reach all your enemies") — the address shifts to the LORD (second person): "your hand." The hand as the instrument of divine power that extends to find and reach every enemy. <strong>יְמִינְךָ תִּמְצָא שֹׂנְאֶיךָ</strong> (<em>yĕmînĕkā timṣāʾ śōnĕʾêkā</em>, "your right hand will seize those who hate you") — the right hand (<em>yāmîn</em>): the hand of power and authority (Ps 18:35: the right hand held the Psalmist up). Here it is the right hand that finds the enemy — the divine arm extended in judgment.</p>',
    "9": '<p><strong>תְּשִׁיתֵמוֹ כְּתַנּוּר אֵשׁ</strong> (<em>tĕshîtêmô kĕtannûr ʾêsh</em>, "You will make them like a burning oven") — <em>tannûr</em>: an oven/furnace (used for baking bread; also for smelting). The enemies as fuel for an oven at the time of the LORD\'s appearance (<em>lĕʿêt pānêkā</em>: "in the time of your face/presence"). <strong>יְהוָה בְּאַפּוֹ יְבַלְּעֵם</strong> (<em>YHWH bĕʾappô yĕballĕʿêm</em>, "the LORD in his wrath will swallow them up") — <em>bālaʿ</em> (piel: to swallow, to engulf): total destruction by being consumed. <em>ʾAp</em> (nostril/anger): the burning anger of Ps 18:8.</p>',
    "10": '<p><strong>פִּרְיָמוֹ מֵאֶרֶץ תְּאַבֵּד</strong> (<em>piryāmô mêʾereṣ tĕʾabbêd</em>, "You will destroy their offspring from the earth") — <em>pĕrî</em>: fruit, offspring; <em>ʾābad</em> (piel: to destroy, to cause to perish). The destruction is total and extends to the next generation. <strong>וְזַרְעָם מִבְּנֵי אָדָם</strong> (<em>wĕzarʿām mibbĕnê ʾādām</em>, "their descendants from among mankind") — <em>zeraʿ</em>: seed, offspring, descendants. Both terms (offspring and seed) cover the complete lineage.</p>',
    "11": '<p><strong>כִּי-נָטוּ עָלֶיךָ רָעָה</strong> (<em>kî-nāṭû ʿālêkā rāʿāh</em>, "For they intended evil against you") — the reason for judgment: their intent (<em>nāṭāh</em>: to incline, to aim) was evil directed at the LORD himself, not merely at the king. The king\'s enemies are by that fact enemies of the LORD — the Davidic covenant means that attacking the king is attacking God\'s anointed. <strong>חָשְׁבוּ מְזִמָּה בַּל-יוּכָלוּ</strong> (<em>ḥāshĕbû mĕzimmāh bal-yûkālû</em>, "devised a plot they cannot carry out") — <em>zāmam</em>: to devise, plan (often with evil intent); <em>mĕzimmāh</em>: scheme/device. Their scheming cannot succeed.</p>',
    "12": '<p><strong>כִּי-תְשִׁיתֵמוֹ שֶׁכֶם</strong> (<em>kî-tĕshîtêmô shekem</em>, "You will put them to flight") — <em>shekem</em>: shoulder/back (here used idiomatically for putting someone to retreat — "turning the shoulder/back"). <strong>בְּמֵיתָרֶיךָ תְּכוֹנֵן עַל-פְּנֵיהֶם</strong> (<em>bĕmêtārêkā tĕkônên ʿal-pĕnêhem</em>, "as you aim your bow at their faces") — <em>mêtār</em>: a bow-string; the image of aiming the bow directly at their faces.</p>',
    "13": '<p><strong>רוּמָה יְהוָה בְּעֻזֶּךָ</strong> (<em>rûmāh YHWH bĕʿuzzekā</em>, "Rise in your strength, O LORD!") — the psalm ends with a call and a response. <em>Rûm</em> (hiphil imperative: to lift yourself up, to be exalted) echoing Ps 3:7 (<em>qûmāh YHWH</em>) and Ps 7:6 (<em>qûmāh YHWH</em>). <strong>נָשִׁירָה וּנְזַמְּרָה גְּבוּרָתֶךָ</strong> (<em>nāshîrāh ûnĕzammĕrāh gĕbûrātekā</em>, "We will sing and praise your mighty deeds") — <em>shîr</em> (to sing) and <em>zāmar</em> (to sing with instrumental accompaniment — the word from which <em>mizmôr</em> comes): the full liturgical response of the congregation to the divine strength. The psalm closes the pre-battle liturgy cycle (Ps 20-21) with a vow to sing after the victory God provides.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    for ch in range(18, 22):
        print(f"  ch{ch}: {len(existing.get(str(ch), {}))} verses")
    print('Psalms 18-21 mkt-original written.')

if __name__ == '__main__':
    main()
